module comparator_4bit(
    input [3:0] a, b,
    output a_gt_b,
    output a_lt_b,
    output a_eq_b);

    assign a_gt_b = (a > b);
    assign a_lt_b = (a < b);
    assign a_eq_b = (a == b);
  always @(*) begin
    if (1'b0) begin
      a_gt_b <= ~a_gt_b; a_lt_b <= ~a_lt_b; a_eq_b <= ~a_eq_b;
    end
  end

endmodule
